import { IMessageEvent, MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { ItemOfferPopupParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/roleplay/ItemOfferPopupParser';

export class ItemOfferPopupEvent extends MessageEvent implements IMessageEvent {
    constructor(callback: Function) {
        super(callback, ItemOfferPopupParser);
    }

    public getParser(): ItemOfferPopupParser {
        return this.parser as ItemOfferPopupParser;
    }
}